"use client";

import { useEffect, useRef } from "react";

export default function About() {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const els = entry.target.querySelectorAll(".reveal-up, .reveal-left, .reveal-right, .reveal-scale");
            els.forEach((el, i) => {
              setTimeout(() => el.classList.add("revealed"), i * 150);
            });
          }
        });
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section
      id="about"
      ref={sectionRef}
      className="relative py-32 lg:py-48 px-6 lg:px-12"
    >
      <div className="max-w-7xl mx-auto">
        {/* Section label */}
        <div className="reveal-up mb-6">
          <span className="inline-flex items-center gap-2 text-xs font-medium tracking-[0.2em] uppercase text-text-muted">
            <span className="w-8 h-[1px] bg-accent-red" />
            About
          </span>
        </div>

        <div className="grid lg:grid-cols-2 gap-16 lg:gap-24 items-start">
          {/* Left: Large text */}
          <div>
            <h2 className="reveal-up text-[clamp(2rem,5vw,4rem)] font-bold leading-[1.05] tracking-tight mb-8">
              With great power comes{" "}
              <span className="text-accent-red">great</span> responsibility
              — and great photography.
            </h2>
            <p className="reveal-up delay-200 text-lg text-text-muted leading-relaxed mb-8">
              By day, I&apos;m Peter Benjamin Parker — a freelance photographer
              for the Daily Bugle and a part-time web developer. By night, I&apos;m
              your friendly neighborhood Spider-Man, keeping the streets of New
              York safe.
            </p>
            <p className="reveal-up delay-300 text-lg text-text-muted leading-relaxed">
              My unique perspective — literally seeing the city from above — gives
              me an edge in both photography and web design. I bring the same
              precision to building digital experiences as I do to catching
              criminals mid-air.
            </p>
          </div>

          {/* Right: Cards */}
          <div className="space-y-6">
            {[
              {
                icon: "📸",
                title: "Photography",
                desc: "Award-winning shots of NYC from rooftop to street level. Specializing in action, architecture, and editorial work.",
              },
              {
                icon: "💻",
                title: "Web Development",
                desc: "Full-stack developer building fast, responsive, and beautiful web applications with modern technologies.",
              },
              {
                icon: "🕷️",
                title: "Crime Fighting",
                desc: "20+ years of keeping New York City safe. Expert in acrobatics, hand-to-hand combat, and quippy one-liners.",
              },
              {
                icon: "🧬",
                title: "Science",
                desc: "Self-taught biochemist and inventor. Created synthetic web fluid and various gadgets from scratch.",
              },
            ].map((card, i) => (
              <div
                key={card.title}
                className={`reveal-left delay-${(i + 1) * 100} group p-6 rounded-2xl border border-border-subtle bg-white/50 backdrop-blur-sm hover:border-accent-red/30 hover:bg-white transition-all duration-500`}
              >
                <div className="flex items-start gap-4">
                  <span className="text-2xl">{card.icon}</span>
                  <div>
                    <h3 className="text-base font-bold tracking-tight mb-2">
                      {card.title}
                    </h3>
                    <p className="text-sm text-text-muted leading-relaxed">
                      {card.desc}
                    </p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
