"use client";

import { useEffect, useState } from "react";

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
      const maxScroll =
        document.documentElement.scrollHeight - window.innerHeight;
      setProgress(maxScroll > 0 ? window.scrollY / maxScroll : 0);
    };
    window.addEventListener("scroll", handleScroll, { passive: true });
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        scrolled
          ? "bg-white/80 backdrop-blur-xl border-b border-border-subtle"
          : "bg-transparent"
      }`}
    >
      {/* Progress bar */}
      <div
        className="absolute bottom-0 left-0 h-[2px] bg-accent-red transition-none"
        style={{ width: `${progress * 100}%` }}
      />

      <div className="max-w-7xl mx-auto px-6 lg:px-12 h-16 flex items-center justify-between">
        {/* Logo */}
        <a href="#hero" className="flex items-center gap-3 group">
          <div className="w-8 h-8 rounded-full bg-accent-red flex items-center justify-center transition-transform duration-300 group-hover:scale-110">
            <svg
              viewBox="0 0 24 24"
              className="w-4 h-4 text-white fill-current"
            >
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z" />
            </svg>
          </div>
          <span className="text-sm font-semibold tracking-widest uppercase hidden sm:block">
            P. Parker
          </span>
        </a>

        {/* Links */}
        <div className="flex items-center gap-8">
          {["About", "Work", "Skills", "Contact"].map((item) => (
            <a
              key={item}
              href={`#${item.toLowerCase()}`}
              className="text-xs font-medium tracking-widest uppercase text-text-muted hover:text-foreground transition-colors duration-300 hidden sm:block"
            >
              {item}
            </a>
          ))}
          <a
            href="mailto:peter@dailybugle.com"
            className="text-xs font-medium tracking-widest uppercase bg-accent-red text-white px-5 py-2.5 rounded-full hover:bg-red-700 transition-all duration-300 magnetic-btn"
          >
            Hire Me
          </a>
        </div>
      </div>
    </nav>
  );
}
