"use client";

import { useEffect, useRef } from "react";

export default function Skills() {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const els = entry.target.querySelectorAll(
              ".reveal-up, .reveal-left, .reveal-right, .reveal-scale"
            );
            els.forEach((el, i) => {
              setTimeout(() => el.classList.add("revealed"), i * 150);
            });
          }
        });
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  const skillGroups = [
    {
      title: "Development",
      skills: [
        { name: "TypeScript / React", level: 95 },
        { name: "Next.js / Node.js", level: 90 },
        { name: "Python / TensorFlow", level: 80 },
        { name: "PostgreSQL / MongoDB", level: 85 },
        { name: "Three.js / WebGL", level: 75 },
        { name: "HTML / CSS / Tailwind", level: 98 },
      ],
    },
    {
      title: "Creative",
      skills: [
        { name: "Photography", level: 95 },
        { name: "UI/UX Design", level: 88 },
        { name: "Figma / Adobe CC", level: 85 },
        { name: "Motion Design", level: 78 },
        { name: "Brand Identity", level: 82 },
        { name: "Print Design", level: 70 },
      ],
    },
    {
      title: "Superpowers",
      skills: [
        { name: "Wall Crawling", level: 100 },
        { name: "Spider-Sense", level: 99 },
        { name: "Super Strength", level: 92 },
        { name: "Acrobatics", level: 97 },
        { name: "Web Fluid Chemistry", level: 88 },
        { name: "Quippy One-Liners", level: 100 },
      ],
    },
  ];

  return (
    <section
      id="skills"
      ref={sectionRef}
      className="relative py-32 lg:py-48 px-6 lg:px-12"
    >
      <div className="max-w-7xl mx-auto">
        {/* Section label */}
        <div className="reveal-up mb-6">
          <span className="inline-flex items-center gap-2 text-xs font-medium tracking-[0.2em] uppercase text-text-muted">
            <span className="w-8 h-[1px] bg-accent-red" />
            Capabilities
          </span>
        </div>

        <h2 className="reveal-up text-[clamp(2rem,5vw,4rem)] font-bold leading-[1.05] tracking-tight mb-20 max-w-3xl">
          What I bring to <span className="text-accent-red">every</span>{" "}
          project.
        </h2>

        {/* Skill groups grid */}
        <div className="grid lg:grid-cols-3 gap-16 lg:gap-12">
          {skillGroups.map((group, gi) => (
            <div key={group.title} className="reveal-up" style={{ transitionDelay: `${gi * 200}ms` }}>
              <h3 className="text-xs font-bold tracking-[0.25em] uppercase text-accent-red mb-10">
                {group.title}
              </h3>
              <div className="space-y-8">
                {group.skills.map((skill, si) => (
                  <div key={skill.name}>
                    <div className="flex justify-between items-baseline mb-3">
                      <span className="text-sm font-medium tracking-tight">
                        {skill.name}
                      </span>
                      <span className="text-xs font-mono text-text-muted">
                        {skill.level}%
                      </span>
                    </div>
                    <div className="h-[2px] bg-border-subtle rounded-full overflow-hidden">
                      <div
                        className="h-full bg-gradient-to-r from-accent-red to-accent-red/60 rounded-full transition-all duration-1000 ease-out"
                        style={{
                          width: `${skill.level}%`,
                          transitionDelay: `${gi * 200 + si * 100}ms`,
                        }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        {/* Marquee ticker */}
        <div className="reveal-up mt-32 overflow-hidden py-8 border-t border-border-subtle">
          <div className="marquee-track flex whitespace-nowrap">
            {Array.from({ length: 2 }).map((_, setIndex) => (
              <span key={setIndex} className="flex items-center gap-8 mr-8">
                {[
                  "React",
                  "TypeScript",
                  "Next.js",
                  "Three.js",
                  "Photography",
                  "Node.js",
                  "Python",
                  "Figma",
                  "Tailwind",
                  "PostgreSQL",
                  "WebGL",
                  "GSAP",
                ].map((item) => (
                  <span
                    key={`${setIndex}-${item}`}
                    className="text-sm font-medium tracking-wider uppercase text-text-muted/40"
                  >
                    {item}
                    <span className="mx-4 text-accent-red/30">●</span>
                  </span>
                ))}
              </span>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
