"use client";

import { useEffect, useRef } from "react";

export default function Hero() {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const els = entry.target.querySelectorAll(".reveal-up");
            els.forEach((el, i) => {
              setTimeout(() => el.classList.add("revealed"), i * 150);
            });
          }
        });
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section
      id="hero"
      ref={sectionRef}
      className="relative min-h-screen flex flex-col justify-center px-6 lg:px-12 max-w-7xl mx-auto"
    >
      {/* Top tag */}
      <div className="reveal-up delay-100 mb-8">
        <span className="inline-flex items-center gap-2 text-xs font-medium tracking-[0.2em] uppercase text-text-muted">
          <span className="w-8 h-[1px] bg-accent-red" />
          Available for freelance work
        </span>
      </div>

      {/* Main headline */}
      <h1 className="text-[clamp(3rem,8vw,8rem)] font-bold leading-[0.9] tracking-tight mb-8">
        <span className="reveal-up delay-200 block">
          Peter
        </span>
        <span className="reveal-up delay-300 block text-accent-red">
          Parker
        </span>
      </h1>

      {/* Subtitle */}
      <div className="reveal-up delay-400 max-w-xl mb-12">
        <p className="text-lg lg:text-xl text-text-muted leading-relaxed">
          Freelance photographer, web developer, and the friendly neighborhood
          Spider-Man. Based in New York City, swinging between code and
          crime-fighting since 2002.
        </p>
      </div>

      {/* Stats row */}
      <div className="reveal-up delay-500 flex flex-wrap gap-12 lg:gap-20 mb-16">
        {[
          { number: "20+", label: "Years Active" },
          { number: "1000+", label: "Saved Lives" },
          { number: "∞", label: "Web Fluid" },
        ].map((stat) => (
          <div key={stat.label}>
            <div className="text-4xl lg:text-5xl font-bold tracking-tight">
              {stat.number}
            </div>
            <div className="text-xs font-medium tracking-[0.2em] uppercase text-text-muted mt-2">
              {stat.label}
            </div>
          </div>
        ))}
      </div>

      {/* CTA */}
      <div className="reveal-up delay-600 flex flex-wrap gap-4">
        <a
          href="#work"
          className="inline-flex items-center gap-3 bg-accent-red text-white px-8 py-4 rounded-full text-sm font-semibold tracking-wider uppercase magnetic-btn hover:bg-red-700 transition-colors duration-300"
        >
          View My Work
          <svg
            className="w-4 h-4"
            fill="none"
            viewBox="0 0 24 24"
            stroke="currentColor"
            strokeWidth={2}
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              d="M19 14l-7 7m0 0l-7-7m7 7V3"
            />
          </svg>
        </a>
        <a
          href="#contact"
          className="inline-flex items-center gap-3 border border-border-subtle px-8 py-4 rounded-full text-sm font-semibold tracking-wider uppercase text-text-muted hover:border-accent-red hover:text-accent-red transition-all duration-300 magnetic-btn"
        >
          Get In Touch
        </a>
      </div>

      {/* Scroll indicator */}
      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 reveal-up delay-600">
        <div className="flex flex-col items-center gap-3">
          <span className="text-[10px] font-medium tracking-[0.3em] uppercase text-text-muted">
            Scroll
          </span>
          <div className="w-[1px] h-12 bg-gradient-to-b from-accent-red to-transparent animate-pulse" />
        </div>
      </div>
    </section>
  );
}
